"use client"

import { useEffect, useMemo, useState } from "react"
import { ArrowUpRight, MessageSquare, RefreshCw, Star, Timer, TrendingUp } from "lucide-react"
import { AdminFrame } from "@/components/dg/admin-frame"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { demoData, requestAdminData } from "@/components/dg/api"

type DashboardState = {
  overview: any
  satisfaction: any
  emotions: Record<string, number>
  hotQuestions: any[]
  interests: Record<string, number>
  hotSpots: any[]
  source: "backend" | "demo" | "mixed" | "loading"
}

const initialState: DashboardState = {
  overview: demoData.overview,
  satisfaction: demoData.satisfaction,
  emotions: demoData.emotions,
  hotQuestions: demoData.hotQuestions,
  interests: demoData.interests,
  hotSpots: demoData.hotSpots,
  source: "loading",
}

function responseTime(value: unknown) {
  const ms = Number(value)
  if (!Number.isFinite(ms)) return "-"
  return ms >= 1000 ? `${(ms / 1000).toFixed(1)}s` : `${Math.round(ms)}ms`
}

function StatCard({ title, value, note, icon: Icon, active, delay }: any) {
  return (
    <Card
      className={`${active ? "bg-primary text-primary-foreground" : "bg-card text-foreground"} cursor-pointer p-5 shadow-lg transition-all duration-500 ease-out animate-slide-in-up hover:scale-[1.03] hover:shadow-2xl`}
      style={{ animationDelay: delay }}
    >
      <div className="mb-8 flex items-start justify-between">
        <h3 className="text-sm font-medium opacity-90">{title}</h3>
        <div className={`${active ? "bg-primary-foreground/20" : "bg-primary"} flex h-7 w-7 items-center justify-center rounded-full transition-transform duration-300 group-hover:rotate-45`}>
          <ArrowUpRight className="h-3.5 w-3.5 text-primary-foreground" />
        </div>
      </div>
      <p className="mb-6 text-4xl font-bold">{value}</p>
      <div className="flex items-center gap-1.5 text-xs opacity-80">
        <Icon className="h-3.5 w-3.5" />
        <span>{note}</span>
      </div>
    </Card>
  )
}

function BarPanel({ title, label, data }: { title: string; label: string; data: Array<{ name: string; value: number }> }) {
  const max = Math.max(...data.map((item) => item.value), 1)
  return (
    <Card className="animate-slide-in-up bg-gradient-to-br from-background to-muted/20 p-6 shadow-lg transition-all duration-500 hover:shadow-xl">
      <div className="mb-6 flex items-center justify-between">
        <h2 className="text-xl font-semibold text-foreground">{title}</h2>
        <div className="flex items-center gap-2 text-xs text-muted-foreground">
          <span className="h-2 w-2 rounded-full bg-emerald-600" />
          <span>{label}</span>
        </div>
      </div>
      <div className="flex h-64 items-end gap-4 border-b border-muted/50 px-3 pb-4">
        {data.map((item, index) => (
          <div key={item.name} className="group flex h-full flex-1 flex-col items-center justify-end gap-2">
            <div
              className="w-full max-w-16 rounded-xl bg-primary transition-all duration-500 group-hover:brightness-110 group-hover:drop-shadow-lg"
              style={{
                height: `${Math.max(8, (item.value / max) * 100)}%`,
                backgroundColor: ["#059669", "#047857", "#10b981", "#065f46"][index % 4],
              }}
              title={`${item.name}: ${item.value}`}
            />
            <span className="text-xs text-muted-foreground">{item.name}</span>
          </div>
        ))}
      </div>
    </Card>
  )
}

export function DashboardContent() {
  const [state, setState] = useState<DashboardState>(initialState)
  const [loading, setLoading] = useState(false)

  async function load() {
    setLoading(true)
    const results = await Promise.all([
      requestAdminData("/api/admin/stats/overview?range=today", demoData.overview),
      requestAdminData("/api/admin/stats/satisfaction?range=week", demoData.satisfaction),
      requestAdminData("/api/admin/stats/emotion-trend?range=week", { distribution: demoData.emotions }),
      requestAdminData("/api/admin/stats/hot-questions?range=week&limit=8", { items: demoData.hotQuestions }),
      requestAdminData("/api/admin/stats/interest-distribution?range=month", demoData.interests),
      requestAdminData("/api/admin/stats/hot-spots?range=week&limit=7", { items: demoData.hotSpots }),
    ])
    setState({
      overview: results[0].data,
      satisfaction: results[1].data,
      emotions: (results[2].data as any).distribution || demoData.emotions,
      hotQuestions: (results[3].data as any).items || [],
      interests: results[4].data as any,
      hotSpots: (results[5].data as any).items || [],
      source: results.some((item) => item.source === "demo") ? "mixed" : "backend",
    })
    setLoading(false)
  }

  useEffect(() => {
    load()
  }, [])

  const stats = useMemo(() => {
    const rag = state.overview.rag_hit_rate == null ? "-" : `${Math.round(Number(state.overview.rag_hit_rate) * 100)}%`
    return [
      { title: "总会话", value: state.overview.total_conversations ?? 0, note: "今日创建的游客会话", icon: MessageSquare, active: true },
      { title: "总消息", value: state.overview.total_messages ?? 0, note: "游客与 AI 消息总量", icon: TrendingUp },
      { title: "平均响应", value: responseTime(state.overview.avg_response_ms), note: "后端平均响应耗时", icon: Timer },
      { title: "满意度", value: state.overview.avg_satisfaction == null ? "-" : Number(state.overview.avg_satisfaction).toFixed(1), note: `RAG 命中率 ${rag}`, icon: Star },
    ]
  }, [state.overview])

  const satisfactionBars = (state.satisfaction.trend || []).map((item: any) => ({
    name: String(item.date || "").replace("周", ""),
    value: Number(item.avg_rating || 0) * 20,
  }))
  const interestBars = Object.entries(state.interests || {}).map(([name, value]) => ({ name, value: Number(value) }))

  return (
    <AdminFrame
      title="Dashboard"
      description="查看导览服务运行情况、游客偏好与知识命中表现。"
      actions={
        <>
          <Button onClick={load} disabled={loading} className="h-9 transition-all duration-300 hover:scale-105 hover:shadow-lg hover:shadow-primary/30">
            <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
            刷新数据
          </Button>
          <Button variant="outline" className="h-9 bg-transparent">
            {state.source === "backend" ? "后端实时数据" : state.source === "mixed" ? "部分演示数据" : "正在读取数据"}
          </Button>
        </>
      }
    >
      <div className="space-y-4">
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-4">
          {stats.map((item, index) => (
            <StatCard key={item.title} {...item} delay={`${index * 100}ms`} />
          ))}
        </div>
        <div className="grid grid-cols-1 gap-4 lg:grid-cols-3">
          <div className="lg:col-span-2">
            <BarPanel title="满意度趋势" label="最近 7 天" data={satisfactionBars} />
          </div>
          <Card className="animate-slide-in-up p-6 shadow-lg transition-all duration-500 hover:shadow-xl" style={{ animationDelay: "500ms" }}>
            <h2 className="mb-6 text-xl font-semibold">热门问题</h2>
            <div className="space-y-3">
              {state.hotQuestions.slice(0, 5).map((item, index) => (
                <div key={`${item.question_pattern}-${index}`} className="rounded-lg border border-border p-3 transition-all duration-300 hover:scale-[1.02] hover:bg-secondary">
                  <p className="text-sm font-medium">{item.question_pattern}</p>
                  <p className="mt-1 text-xs text-muted-foreground">{item.count} 次咨询</p>
                </div>
              ))}
            </div>
          </Card>
        </div>
        <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
          <BarPanel title="兴趣分布" label="最近 30 天" data={interestBars} />
          <Card className="animate-slide-in-up p-6 shadow-lg transition-all duration-500 hover:shadow-xl">
            <h2 className="mb-6 text-xl font-semibold">热门景点</h2>
            <div className="space-y-4">
              {state.hotSpots.map((item, index) => (
                <div key={`${item.spot_name}-${index}`} className="grid grid-cols-[28px_1fr_48px] items-center gap-3 text-sm">
                  <span className="font-bold text-primary">{index + 1}</span>
                  <div className="h-3 overflow-hidden rounded-full bg-muted">
                    <div className="h-full rounded-full bg-primary" style={{ width: `${Math.min(100, Number(item.mention_count || 0) / 2.4)}%` }} />
                  </div>
                  <span className="text-right text-muted-foreground">{item.mention_count}</span>
                  <strong className="col-start-2 -mt-2 truncate">{item.spot_name}</strong>
                </div>
              ))}
            </div>
          </Card>
        </div>
      </div>
    </AdminFrame>
  )
}
